
import ViewBase from "../../engine/ViewBase";
import VideoAdSystem from "../../System/VideoAd/VideoAdManager";
import GameData from "../GameData";

const {ccclass, property} = cc._decorator;

@ccclass
export default class ExtraTimeView extends ViewBase {

	@property({ type: cc.Sprite, displayName:'关闭按钮' })
	closeBtn: cc.Sprite = null;

	@property({ type: cc.Sprite, displayName:'返回主页按钮' })
	homeBtn: cc.Sprite = null;

	@property({ type: cc.Sprite, displayName:'跳过关卡按钮' })
	skipBtn: cc.Sprite = null;

    start () {
		
		this.onAddEvent(this.closeBtn.node,()=>{
			this.closeView();
		});

		this.onAddEvent(this.homeBtn.node,()=>{
			// 返回主页逻辑
			GameData.CurGM.EndGame();
			GameData.CurGM = null;
			this.closeView();
			// 这里可以添加跳转到主页的逻辑
		});

		this.onAddEvent(this.skipBtn.node,async ()=>{
			let scucess = await VideoAdSystem.PlayerVideoAd();
			if(!scucess) return;
			
			this.isValid && this.closeView();
			GameData.CurGM.gotoNextLevel();
		});
		
		if(!GameData.CurGM.hasNextLevel()){
			this.skipBtn.getComponent(cc.Button).interactable = false;
		}
    }
	
	onInitChild(level: number){
	}

}
