const { ccclass, property } = cc._decorator;

@ccclass
export default class SpriteframeCom extends cc.Component {
    @property({ type: [cc.SpriteFrame] })
    public spriteFrameList: Array<cc.SpriteFrame> = []
    private indexNext_SpriteFrameList: number = 0;

    protected onLoad(): void {
        // 节点未激活时使用next出错
        // this.indexNext_SpriteFrameList = 0;
        // this.length_spriteFrameList = this.spriteFrameList.length;
    }

    public Excute() {

    }

    public Next() {
        let spriteFrame = this.spriteFrameList[this.indexNext_SpriteFrameList];
        if(spriteFrame == null){
            console.error("SpriteframeCom: 切换失败",this, this.indexNext_SpriteFrameList);
            return;
        }
        this.node.getComponent(cc.Sprite).spriteFrame = spriteFrame;
        this.indexNext_SpriteFrameList += 1;
        if (this.indexNext_SpriteFrameList >= this.spriteFrameList.length) {
            this.indexNext_SpriteFrameList = 0;
        }
        return this;
    }

    public resetAnchor() {
        this.node.setAnchorPoint(0.5, 0.5);
    }

}