import ResourcesManager from "../../engine/ResourceManager";
import ViewBase from "../../engine/ViewBase";
import { HintConfig, LevelConfig } from "../../gamePlaySystem/GameAttribute";
import { BasicGameManger } from "../../gamePlaySystem/GameManager/BasicGameManger";
import Singleton from "../../singleton/Singleton";
import UIManager from "../../System/ui/UIManager";
import { ViewConfig } from "../../System/ui/UI_Config";
import Timer from "../../Tools/Timer";
import GameData from "../GameData";
import VideoAdSystem from "../../System/VideoAd/VideoAdManager";

const {ccclass, property} = cc._decorator;

@ccclass
export default class GameMenuPanel extends ViewBase {

	@property({ type: cc.Node, displayName:'' })
	restartBtn: cc.Node = null;

	@property({ type: cc.Sprite, displayName:'' })
	homeBtn: cc.Sprite = null;

	@property({ type: cc.Sprite, displayName:'' })
	closeBtn: cc.Sprite = null;

	@property({ type: cc.Sprite, displayName:'' })
	passBtn: cc.Sprite = null;

	@property({ type: cc.Sprite, displayName:'' })
	resumeBtn: cc.Sprite = null;

	onLoad(){

		this.onAddEvent(this.closeBtn.node,()=>{
			this.closeView();
			GameData.CurGM.resume();
		});

		this.onAddEvent(this.passBtn.node,async ()=>{
			let scucess = await VideoAdSystem.PlayerVideoAd();
			if(!scucess) return;
			
			this.isValid && this.closeView();
			GameData.CurGM.gotoNextLevel();
		});


		this.onAddEvent(this.restartBtn, async () => {
			this.isValid && this.closeView();
			GameData.gotoLevel(GameData.CurGM.Level);
		});

		this.onAddEvent(this.resumeBtn.node,()=>{
			this.closeView();
			GameData.CurGM.resume();
		});

		this.onAddEvent(this.homeBtn.node,()=>{
			GameData.CurGM.EndGame();
			GameData.CurGM = null;	
			this.closeView();
            UIManager.instance.showView(ViewConfig.HomeView,()=>{})
		});

		if(!GameData.CurGM.hasNextLevel()){
			this.passBtn.getComponent(cc.Button).interactable = false;
		}
	}

	onInitChild(level: string){
		GameData.CurGM.pause()
	}

	onDestroy(){
		Timer.clearAll(this);
		console.log("GameView onDestroy")
	}


}
