import Timer from "../../Tools/Timer";
import Tools from "../../Tools/Tools";
import { DebugLogSystem } from "../../engine/DebugLogManager";
import { EventManager } from "../../engine/EventManager";
import { Logger, Debug } from "../../engine/Logger";
import UIData from "../../game/fgui/GameUIEnum";
import Singleton from "../../singleton/Singleton";
import SingletonAttribute from "../../singleton/SingletonAttribute";
import GameEventSystem from "../GameEvent/GameEvent";
import FGUIEvent from "./FGUIEvent";
import FGUIManager from "./FGUIManager";
import FguiButton from "./FguiButtom";
import { FguiButton2 } from "./FguiButton2";

/** 仅用于监听ui释放 */
class NodeComp extends cc.Component {
    public onDisableCallback: ()=>any;
    public onDestroyCallback: ()=>any;
    protected onDisable(): void {
        this.onDisableCallback && this.onDisableCallback()
    }
    protected onDestroy(): void {
        this.onDestroyCallback && this.onDestroyCallback()
    }
}

export default abstract class BaseUI {

    public name = "";
    public uievent: EventManager;

    protected view: fgui.GComponent;
    public get View(): fgui.GComponent {
        return this.view;
    }
    protected father: BaseUI
    protected inview: boolean;
    protected ready_open: boolean;
    protected tag: string;
    protected dispose: boolean;
    protected is_destroy: boolean;
    // 异步的数据
    protected async_finish: boolean;
    protected async_open: boolean;
    protected async_args: any;

    //为了当前touchable false的时候 不穿透下层
    protected touchMaskCom: fgui.GGraph;

    protected nodeComp: NodeComp;

    // 当前是第几层
    protected cur_layer: number;
    private _btnComArr: FguiButton[];

    // 大图
    protected big_bg_url : string = null;

    public get Opening() : boolean{
        return this.inview || this.ready_open;
    }

    /** UI是否有效 */
    public get IsVaild(){
        return !this.dispose && this.view && this.view.node && this.view.node["$gobj"] && this.view.node.isValid; 
    }

    constructor(tag: string, pkgname: string, resname: string, width: number = fgui.GRoot.inst.width, height: number = fgui.GRoot.inst.height , async : boolean = false) {
        this.async_finish = false;
        this.async_open = false;
        this.dispose = false;
        this.tag = tag;
        this.name = resname;
        if (async) {
            this.UILoadSucc(fgui.UIPackage.createObject(pkgname, resname), width, height);
        } else {
            let _handle = new fgui.AsyncOperation();
            _handle.callback = this.UILoadSucc.bind(this, width, height);
            _handle.createObject(pkgname, resname);
        }

    }

    private UILoadSucc(obj: fgui.GObject, _w: number, _h: number) {
        if (this.dispose) {
            // 已经删了界面
            obj.dispose();
            return;
        }
        this.view = obj.asCom;
        let _width = _w || fgui.GRoot.inst.width;
        let _height = _h || fgui.GRoot.inst.height;

        this.view.setSize(_width, _height);
        this.view.node.name = this.constructor.name;
        this.view.node['_fgui'] = this;

        this.touchMaskCom == null && (this.touchMaskCom = new fgui.GGraph());
        this.touchMaskCom.touchable = true;
        this.touchMaskCom.setSize(_width, _height);
        this.touchMaskCom.drawRect(1, cc.Color.TRANSPARENT, cc.Color.TRANSPARENT);
        this.touchMaskCom.alpha = 0;
        this.touchMaskCom.node.on(cc.Node.EventType.TOUCH_END, () => { }, this);
        this.touchMaskCom.node.on(cc.Node.EventType.TOUCH_START, () => { }, this);
        this.touchMaskCom.node.name = 'touchMaskCom';
        this.view.setSize(_width, _height);

        this.nodeComp = this.view.node.addComponent(NodeComp);
        this.nodeComp.onDisableCallback = this.onDisable.bind(this);
        this.nodeComp.onDestroyCallback = this.onDestroy.bind(this);

        this.inview = false;
        this.uievent = new EventManager();
        FGUIManager.FindAndSetFGUILabelColor(this.view);

        this.Init();
        this.async_finish = true;
        if (this.async_open) {
            this.OpenView(this.father, this.async_args);
        }
    }

    /**初始化数据 */
    protected abstract Init();

    /**
     * 打开UI
     * @param father 根节点，默认是fgui的单例节点
     */
    public OpenView(father: BaseUI = null, ...args) {

        this.father = father;
        if (!this.async_finish) {
            this.async_open = true;
            this.async_args = args;
            return;
        } else {
            this.async_args = null;
        }
        // CheckPopupWindow 回调前调用closeview 则不再执行后续流程
        this.inview = true;
        this.ready_open = false;
        
        if (this.father) {
            this.father.view.addChild(this.touchMaskCom);
            this.father.view.addChild(this.view);
            this.cur_layer = this.father.view.numChildren - 1;
        } else {
            fgui.GRoot.inst.root.addChild(this.touchMaskCom);
            fgui.GRoot.inst.root.addChild(this.view);
            this.cur_layer = fgui.GRoot.inst.root.numChildren - 1;
        }
        // this.name 在移动端 == “”, 不能使用
        this.uievent.event(FGUIEvent.UIEVENT_OPENVIEW, this.name);
        // UIManager.Event.event(UIEvent.UIEVENT_OPENVIEW, this.name);
    
        // 设置当前帧渲染前再调用Open, callLater 控制OpenView后再执行Open;
        Timer.callLater(this, ()=> this.inview && this.IsVaild && this.Open() , 1000);
        Timer.loop(100 , this , this.BaseUpdate);
        Singleton.GameEventSystem.dispatch(FGUIEvent.UIEVENT_OPENVIEW , this.tag , this);
        // Logger.warn("打开界面：",this.constructor.name)
        CC_DEBUG && Logger.warn("打开界面：",this.constructor.name, "  fugui:", this.name);
    }

    /**
     * 关闭UI
     * @param dispose 是否释放界面
     */
    public CloseView(dispose: boolean = false) {
        Timer.clearAll(this);
        this.ready_open = false;
        if (!this.inview) {
            this.async_open = false;
            this.async_args = null;
            return;
        }

        this.inview = false;
        // 移除节点不删除事件, 防止触摸事件失灵,自动释放事件不会删除 node._touchListener 导致下次添加触摸事件失灵
        this.touchMaskCom && this.touchMaskCom.node.removeFromParent(false);
        this.view.node.removeFromParent(false);

        if (this.father) {
            this.touchMaskCom && this.father.view.removeChild(this.touchMaskCom);
            this.father.view.removeChild(this.view);
        } else {
            this.touchMaskCom && this.touchMaskCom.removeFromParent();
            this.view.removeFromParent();
        }
        this.uievent.event(FGUIEvent.UIEVENT_CLOSEVIEW, this.name);
        Singleton.GameEventSystem.dispatch(FGUIEvent.UIEVENT_CLOSEVIEW, this.tag, this);
        GameEventSystem.clear(this)

        if (dispose) {
            this.Dispose();
            FGUIManager.DeleteUI(this.tag);
            this.CleanBigBg();
        }
    }

    protected CleanBigBg(){
        if(!this.big_bg_url) return;       
        this.big_bg_url && cc.resources.release(this.big_bg_url , cc.Texture2D);
        this.big_bg_url = null;
    }

    protected BaseUpdate(){
        this.CheckTopUI();
        this.UpdateViewFullScene();
    }

    protected CheckTopUI(){
        if(!this.Opening || !this.IsVaild) return;
        let _com = FGUIManager.GetCurTopNoAlphaUI();
        // console.error("GetCurTopNoAlphaUI" , _com , this.name);
        this.view.alpha = _com ? (_com.layer > this.cur_layer ? 0 : 1) : 1;
    }

    protected UpdateViewFullScene(){
        (CC_DEBUG || CC_JSB) && this.view.makeFullScreen();   //屏幕适应
    }

    protected Open(){

    }

    /**外部调用刷新数据 */
    public ReflashView() {

    }

    public UIBtn(name: string, getCom: fgui.GComponent, clickFunc: (com: FguiButton, ...args) => void, ...args):FguiButton2 {
        var btnCom = new FguiButton2(name, getCom, clickFunc, this, ...args);
        if (this._btnComArr == undefined) this._btnComArr = [];
        this._btnComArr.push(btnCom);
        return btnCom;
    }

    protected ClearBtnEvents() {
        if (this._btnComArr) {
            for (let i = 0, len = this._btnComArr.length; i < len; i++) {
                this._btnComArr[i].Dispose();
            }
            this._btnComArr.length = 0;
        }
    }
    public Dispose() {
        if(this.dispose){
            return;
        }
        this.dispose = true;
        Timer.clear(this, this.CheckTopUI);
        this.touchMaskCom && this.touchMaskCom?.dispose();
        this.touchMaskCom = null;
        this.View && this.View.dispose();
        this.ClearBtnEvents();
    }

    /** 当该组件active = false时或节点变为无效时调用 */
    protected onDisable(){
        // 下一帧前执行, 当前处于引擎内部loop中, 避免循环错误等这一帧结束前再处理
        cc.director.once(cc.Director.EVENT_BEFORE_DRAW,()=>{
            if(this.inview){
                if(this.IsVaild){
                    // ui处于打开状态
                    this.CloseView();
                }
                // console.error("onDisable 未正常关闭UI: ", this.tag, this.IsVaild);
            }
        })
        Timer.clearAll(this);
    }
    
    /** node释放后的下一帧 被动调用 */
    protected onDestroy(){
        this.is_destroy = true;
        Timer.clearAll(this);
        if(this.dispose){
            return;   
        }

        if(this.IsVaild){
            if(this.inview){
                // ui处于打开状态, 当前处于引擎内部loop中, 不能处理异常
                // this.CloseView(true); 
                DebugLogSystem.appErrorReport("onDestroy 未正常释放UI: " + this.tag +' '+ this.IsVaild +' '+ this.inview);
            }else{
                // this.Dispose();
            }
        }
        console.error("onDestroy 未正常释放UI: ", this.tag, this.IsVaild, this.inview);
    }
}