import Timer from "../../Tools/Timer";
import Tools from "../../Tools/Tools";
import { Logger } from "../../engine/Logger";
import GameData from "../../game/GameData";
import SpriteframeCom from "../../game/fgui/SpriteframeCom";
import Singleton from "../../singleton/Singleton";
import { LogicBlockCmds, LogicItem } from "../GameAttribute";

/** if判断正则匹配 */
const LogicalMatchReg = /([^()]+)\s*([&\|])\s*([^()]+)/;
const ComparisonMatchReg = /(\w+)\s*([<>=!]+)\s*(\w+|\d+(\.\d+)?)/;
const SpacReg = /\s+/g;

export type HintInfo = {
	type: string;
	pos: cc.Vec2[];
}

export type LocalValue = {
	[key: string]: any;
}

export class BaseLogicBlock {

	protected config: LogicItem;
	protected completedCb: (is_break: boolean)=>any;
	protected selfCompletedCb: ()=>any;
	protected _hintCallback: ()=>HintInfo;
	/**保存 node字段 的节点 */
	protected nodes: cc.Node[] = [];
	protected cmdIdx: number = 1;
	/** 1开头 */
	protected completedCmdCount: number = 1;
	protected isAutoCompleteNode: boolean = true;
	protected _hintInfo: HintInfo;
	protected isValid: boolean = true;
	protected localNodes: {[key: string]: cc.Node} = {};
	protected children: BaseLogicBlock[] = [];
	protected localValue: LocalValue = {};
	protected parent: BaseLogicBlock;
	protected isPlaySound: boolean = true;

	constructor(config: LogicItem, completedCb?: ()=>any, local_nodes?: {[key: string]: cc.Node}, nodes?: cc.Node[], parent?: BaseLogicBlock, localValue?: LocalValue){
		this.config = config;
		this.localNodes = local_nodes;
		this.parent = parent;

		// 本地配置变量初始化
		config.args && (this.localValue = Tools.CopyObject(config.args));
		if(localValue){
			for (const key in localValue) {
				const v = localValue[key];
				this.localValue[key] = v;
			}
		}
		this.completedCb = completedCb;
		GameData.CurGM.addLogicBlock(this);
		
		this.updateNodes();
		// 如果当前模块没有指定nodes, 则使用父级的nodes;
		if(nodes && this.nodes.length == 0){
			this.nodes = nodes;
		}

		/** if else语句分支控制  */
		if(!this.parseIfElse()){
			return
		}
		
		/** 1. 执行当前逻辑块 */
		let key = 'Mode_' + config.mode; // key = Mode_hide | Mode_click ...
		if(this[key]){
			this[key]()
			return;
		}

		if(config.mode){
			console.warn("logic mode not found", config.mode)
		}
		this.onSelfCompleted();
	}

	
	/** if else语句分支控制  */
	parseIfElse(){
		if(!this.config.else || this.parseIf()){
			return true;
		}
		// if判断不通过, 跳过本模块逻辑与cmds, 执行else逻辑
		this.runCmd(this.config.else, this.onCompletedAll.bind(this));
		return false;
	}
	
	/** 2.延迟通知完成 */
	delayComplete(){
		if(this.config.time){
			Timer.once(this.config.time * 1000, this, this.onSelfCompleted);
		}else{
			this.onSelfCompleted();
		}
	}

	/** 执行完后处理 this.nodes 相关数据 */
	onCompletedNode(node: cc.Node){
		/** 关卡全局变量 +1 */
		GameData.CurGM.addValue(node.name)

		/** 把物品显示到ui列表上 */
		
		if(this.config.goods){
			let goods = this.formatValueString(this.config.goods);
			let goods_img = this.formatValueString(this.config.goods_img);
			let spriteframe = this.config.goods_img ? cc.assetManager.getBundle(GameData.CurGM.BundleName).get('img/'+goods_img, cc.SpriteFrame) : node.getComponent(cc.Sprite)?.spriteFrame;
			!spriteframe && console.warn('没有goods_img',spriteframe)
			GameData.CurGM.addGoodsItem(goods, spriteframe);
		}

		/** 执行完后是否隐藏node */
		this.config.hide && (node.active = false);
		//替换图片
		if(this.config.changeSpriteframe){
			let c = node.getComponent(SpriteframeCom)?.Next();
			this.config.resetAnchor && c && c.resetAnchor();
		}

		if(this.config.top != null){
			/** 执行完后置顶node */
			let len = node.children.length-1;
			let top = Math.min(len + Number(this.config.top), len);
			node.parent.insertChild(node, top);
		}else if(this.config.bottom != null){
			/** 执行完后底置node */
			let bottom = Math.max(0, Number(this.config.bottom));
			node.parent.insertChild(node, bottom);
		}
	}
	
	
	/** 3.该模块逻辑执行完 (但cmds子逻辑还未执行) */
	onSelfCompleted(){
		/** 执行完后处理node相关数据 */
		if(this.isAutoCompleteNode){
			this.nodes.forEach(node => this.onCompletedNode(node));
		}

		/** 关卡自定义全局变量 */
		this.config.var && this.operation( this.formatValueString( this.config.var) );

		this.config.sound && this.isPlaySound && this.playSound(this.config.sound);
		
		/** 目前用于隐藏对话框 */
		this.selfCompletedCb && this.selfCompletedCb();

		if(!this.config.cmds || this.config.cmds.length == 0){
			this.onCompletedAll();
			return;
		}else if( this.config.cmds[0] == 'seq'){
			// 4. 顺序执行 子逻辑
			this.onNextCmd();
		}else  if( this.config.cmds[0] == '!seq'){
			if(this.config.cmds.length <= 1) {
				this.onCompletedAll();
			}else{
				// 4. 并行执行 子逻辑
				let cmds = this.config.cmds;
				for (let i = 1; i < cmds.length; i++) {
					const element = cmds[i] as LogicItem | LogicBlockCmds;
					this.runCmd(element, this.onCmdsCompleted.bind(this));
				}
			}
		}else{
			console.error('cmds 配置必须以 seq 或 !seq 开头', this.config.cmds, this.config)
		}
	}

	/** 4. 顺序执行配置中cmds配置 子逻辑 */
	onNextCmd(is_break: boolean = false){
		if(this.config.cmds.length <= 1 || is_break) {
			return this.onCompletedAll();
		}

		let item = this.config.cmds[this.completedCmdCount] as LogicItem | LogicBlockCmds;
		this.completedCmdCount++;
		if(item){
			this.runCmd(item, this.onNextCmd.bind(this));
		}else{
			this.onCompletedAll();
		}
	}

	/** 4. 执行子逻辑 */
	runCmd(item: LogicBlockCmds | LogicItem, completedCb: (is_break?: boolean)=>any, args?: LocalValue){
		let nodes = this.nodes;
		// node名映射，相当于局部node变量
		let local_nodes = this.config.namemap && nodes[0] ? {[this.config.namemap]: nodes[0]} : {};
		if(this.localNodes){
			local_nodes = Object.assign(local_nodes, this.localNodes);
		}
		let logicBlockObj: BaseLogicBlock;
		if(Array.isArray(item)){
			// @ts-ignore
			logicBlockObj = new this.constructor({mode: '', cmds: item}, completedCb, local_nodes, nodes, this);
			this.children && this.children.push(logicBlockObj);
		}else{

			let self = this
			if(item.unlink){
				local_nodes = {};
				nodes = [];
				self = null;
			}

			// @ts-ignore
			logicBlockObj = new this.constructor(item as LogicItem, (is_break: boolean)=>{
				if(is_break){
					// 中断父级cmds流程, 立即执行下一个逻辑
					console.log("中断父级cmds流程, 立即执行下一个逻辑", this.config)
				}
				!item.unlink && completedCb && completedCb(is_break);
			}, local_nodes, nodes, self, args);
			
			if(!item.unlink){
				this.children && this.children.push(logicBlockObj);
			}else{
				// 断开本逻辑上下逻辑关联，不再堵塞流程
				completedCb && completedCb();
			}
		}

	}
	

	/** 4. 并行执行的子逻辑执行完成 */
	onCmdsCompleted(is_break: boolean = false){
		this.completedCmdCount++;
		if(this.completedCmdCount >= this.config.cmds.length || is_break){
			this.onCompletedAll();
		}
	}
	
	/** 5. 所有逻辑执行完成 */
	onCompletedAll(){
		CC_DEBUG && Logger.IsDebugLog && console.log(`mode:${this.config.mode}, 逻辑执行结束, config=`, this.config);
		this.completedCb && this.completedCb(this.config.break);
		this.onDestory();
	}



	/** 1. 获得配置的 node */
	updateNodes(){
		this.getIncludeNodes(this.config.nodeInclude);
		if(!this.config.node) return;
		let nodes = this.config.node.replaceAll(' ','').split('&').map((v)=>{
			return this.getNode(v);
		});
		this.nodes = this.nodes ? this.nodes.concat(nodes) : nodes
	}

	private getIncludeNodes(str: string){
		// let node = this.localNodes && this.localNodes[arr[0]] || GameData.CurGM.getNode(arr[0]);
		GameData.CurGM.getNodes(str);
		for (const key in this.localNodes) {
			if (Object.prototype.hasOwnProperty.call(this.localNodes, key)) {
				key.includes(str) && this.nodes.push(this.localNodes[key]);
			}
		}

	}

	
	/** 获得配置的if条件结果 */
	parseIf(if_str?: string){
		if_str = if_str || this.config.if;
		if(!if_str){
			return true;
		}
		return this.evaluateExpression(if_str);
	}

	/** 等待if条件成立 */
	awaitParseIf(has_log: boolean = true){
		return new Promise((resolve, reject)=>{
			if(this.parseIf()){
				resolve(true);
			}else{
				Timer.loop(500, resolve, ()=>{
					if(!this.isValid){
						Timer.clearAll(resolve);
						return;
					}
					if(this.parseIf()){
						Timer.clearAll(resolve);
						resolve(true);
					}else{
						has_log && Logger.IsDebugLog && console.log(`mode: ${this.config.mode}, if表达式不满足, 等待条件满足后再跑后续流程, config=`, this.config);
					}
				});
			}
		})
	}

	/** if 判断解析函数，用于评估表达式  
	 * @param expr 表达式，例子: expr = "msgBg & count>=10 | bus<=3 & people==2"
	 */ 
	evaluateExpression(expr: string) {  
		// 递归地处理逻辑运算符  
		let evaluateLogical = (left, op, right)=>{  
			let leftValue = (typeof left == 'string') ? this.evaluateExpression(left) : left;  
			let rightValue = (typeof right == 'string') ? this.evaluateExpression(right) : right;  
	
			switch (op) {  
				case "&": return leftValue && rightValue;  
				case "|": return leftValue || rightValue;  
				default: throw new Error("Unknown logical operator: " + op);  
			}  
		}  
	
		// 递归地处理比较运算符  
		let evaluateComparison = (left, op, right)=>{  
			let leftValue = this.getValue(left);  
			let rightValue = this.getValue(right); 

			// 尝试将右侧作为变量或数字  
			leftValue = leftValue != null ? leftValue : parseFloat(left) || parseInt(left, 10);  
			rightValue = rightValue != null ? rightValue : parseFloat(right) || parseInt(right, 10);  
			if(CC_DEBUG && op != '==' && op != '!='  && (isNaN(+leftValue) || isNaN(+rightValue)) ) {
				console.error(`if 表达式变量或数字不存在,if="${expr},\n${left}=${leftValue}, ${right}=${rightValue}"`);  
			}

			switch (op) {  
				case "<": return leftValue < rightValue;  
				case ">": return leftValue > rightValue;  
				case "<=": return leftValue <= rightValue;  
				case ">=": return leftValue >= rightValue;  
				case "==": return leftValue == rightValue;  
				case "!=": return leftValue != rightValue;  
				default: throw new Error("Unknown comparison operator: " + op);  
			}  
		}  
	
		// 递归地处理表达式  
		let recursiveEvaluate = (expr)=>{  
			// 查找逻辑运算符  
			let logicalMatch = LogicalMatchReg.exec(expr);  
			if (logicalMatch) {  
				return evaluateLogical(  
					recursiveEvaluate(logicalMatch[1].trim()),  
					logicalMatch[2],  
					recursiveEvaluate(logicalMatch[3].trim())  
				);  
			}  
	
			// 查找比较运算符  
			let comparisonMatch = ComparisonMatchReg.exec(expr);  
			if (comparisonMatch) {  
				return evaluateComparison(  
					comparisonMatch[1],  
					comparisonMatch[2],  
					comparisonMatch[3]  
				);  
			}  
	
			// 如果表达式是数字，则尝试解析为数字  
			let numberValue = parseFloat(expr) || parseInt(expr, 10);  
			if (!isNaN(numberValue)) {  
				return numberValue;  
			}  

			// 取反符号
			let isNot = expr[0] == '!'; 
			expr = isNot ? expr.substring(1) : expr;
			// 如果表达式是一个变量，则获取其值  
			let val = this.getValue(expr);  
  
			return isNot ? !val : val;  
		}  
	
		return recursiveEvaluate(expr.replace(SpacReg, "")); // 去除所有空格以简化解析  
	}

	/** 运算符 */
	operation(str: string, local_value: boolean = false){

		let [key, expr] = str.split(/[=]/); // 使用正则表达式来分割键和表达式部分;
		key = key[key.length-1].match(/[+-\/*\/]/) ? key.substring(0,key.length-1) : key;
		key = key.trim(); // 去除可能存在的空白字符
		if(expr == null){
			local_value ? this.addLocalValue(key) :GameData.CurGM.addValue(key);
			return;
		}
		expr = expr.trim(); // 去除可能存在的空白字符
		
		// 左边值, 数字或字符串
		let left_args = this.getLocalValue(key, true);
		let left_v = left_args ? left_args.val : GameData.CurGM.getValue(key);
		let l_str_mat: any;
		left_v = left_v != null ? left_v : (l_str_mat = key.match(/['"`](.*)['"`]/)) ? l_str_mat[1] : 0;

		let right_v: any = Number(expr);
		if(isNaN(right_v)){
			// 检测是否是字符串
			let str_mat = expr.match(/['"`](.*)['"`]/);
			right_v = str_mat ? str_mat[1] : this.getValue(key)
		}else{
			right_v = right_v
		}
		
		if (key) { // 如果有键，则是赋值或更新操作  
			let value: number;
			switch (str.charAt(str.indexOf('=') - 1)) {  
				case '-': // 减  
					value = +left_v - right_v;  
				break;  
				case '+': // 累加  
					value = left_v + right_v;  
					break;  
				case '*': // 累乘  
					value = +left_v * right_v;  
					break;  
				case '/': // 相除  
					value = +left_v / right_v;  
					break;  
				default: // 赋值  
					value = right_v;  
					break;  
			}
			// 更新变量值  
			left_args ? left_args.parent.setLocalValue(key, value) : local_value ? this.setLocalValue(key, value) : GameData.CurGM.setValue(key, value);
		} else {  
			// 这里不应该发生，因为我们假设每个字符串都有键  
			// 但如果为了鲁棒性，可以添加错误处理 
			console.error("错误运算符号",str)
		}  
	}

	/** 提示信息 */
	getHintInfo(): HintInfo | any{
		return this._hintCallback && this._hintCallback()//this._hintInfo;
	}

	/** 获取节点 
	 * name = 'root/node1/node2' || 'node1'
	*/
	getNode(name: string){
		name = this.formatValueString(name);
		let arr = name.split('/')
		let node = this.localNodes && this.localNodes[arr[0]] || GameData.CurGM.getNode(arr[0]);
		if(arr.length > 1){
			for (let i = 1; i < arr.length; i++) {
				node = node.getChildByName(arr[i]);
			}
		}
		if(CC_DEBUG && !node){
			console.error(`Mode:${this.config.mode}, 场景中不存在该节点！！:`, name);
		}
		return node;
	}
	
	/** 获取本地变量值 */
	getLocalValue(key: string, is_get_parent: boolean = false){
		let val = this.localValue[key];
		if(val == null){
			if(this.parent){
				return this.parent.getLocalValue(key, is_get_parent)
			}
		}else{
			val = this.formatValueString(val);
		}
		return !is_get_parent ? val : val ? {val, parent: this} : null;
	}

	/** 获取变量值 */
	getValue(key: string){
		let val = this.getLocalValue(key)
		return val != null ? val : GameData.CurGM.getValue(key);
	}

	/** 设置本地变量 */
	setLocalValue(key: string, value: any){
		this.localValue[key] = value;
	}
	
	addLocalValue(key: string){
		this.localValue[key] = this.localValue[key] ? (+this.localValue[key]+1) : 1;
	}
	

	/** 格式化变量值, valueStr = "${count}/数量" 转换为 "1/数量" */
	formatValueString(valueStr: any, defaultValue?: string | number): string{
		return GameData.CurGM.formatValueString(valueStr, defaultValue, this.localNodes, this.getValue.bind(this));
	}
	
	/** 格式化参数变量值, args = {x:"${node.x}", y:${count}, z:0} 转换为 {x:1, y:2, z:0}*/
	formatArgsValue(args: object | Array<any>, convertToNumber: boolean = false): any{
		return GameData.CurGM.formatArgsValue(args, convertToNumber, this.localNodes, this.getValue.bind(this));
	}
	
	/** 播放音效 */
	playSound(fileName: string){
		let path = 'sound/'+fileName;
		if(cc.resources.getInfoWithPath(path)){
			Singleton.SoundSystem.PlaySound("resources", path);
		}else if(cc.assetManager.getBundle(GameData.CurGM.BundleName).getInfoWithPath(path)){
			Singleton.SoundSystem.PlaySound(GameData.CurGM.BundleName, path);
		}else{
			console.error(`播放音效失败: ${fileName}`);
		}
	}

	/** 7. 销毁 */
	onDestory(){
		if(!this.isValid){
			return;
		}

		this._hintCallback = null;
		this.isValid = false;
		Timer.clearAll(this);

		this.children.forEach((child)=>{
			child.isValid && child.onDestory();
		});
		this.children = null;
		this.nodes.forEach((node)=>{ 
			node.isValid && node.targetOff(this); 
		});
		this.nodes = null;
		this.config = null;
		GameData.CurGM.removeLogicBlock(this);
	}
	
}
