
/** 定时器工具 */
export default class Timer {

    /**
     * 两帧之间的时间间隔,单位毫秒。1000ms 非小数 
     * @return {int}
     */
    static get delta(): number {
        // cc.director.getScheduler().setTimeScale 
        return cc.director.getDeltaTime() * 1000;
    }

    /**
     * 帧间隔: 从当前帧开始执行到现在所经过的时间,单位毫秒。1000ms
     */
    static get frameDt(): number {
        // 当前时间 - 当前帧开始时间
        return performance.now() - cc.director['_lastUpdate'];
    }

    static get scale(): number {
        return cc.director.getScheduler().getTimeScale();
    }

    static set scale(v) {
        cc.director.getScheduler().setTimeScale(v);
    }

    private static callLaterEvents: Map<string | number,{eventType: string ,caller:any, method: Function, sourceMethod:Function}> = new Map();
    private static _id: number = 0;
    private static get newId(): number {
        return Timer._id++;
    }

    /**
     * 延迟下一帧执行。
     * @param caller 执行域(this)
     * @param method 定时器回调函数
     * @param idleTime 等到空闲帧后再调用,单位毫秒。1000ms, 在 idleTime 时间内代表空闲帧
     * @param uuid 唯一标识,如果有 那么同一帧内同个uuid多次调用, 只会执行一次
     */
    static callLater(caller: any, method: Function, idleTime?: number, uuid?: string) {
        if (!(method instanceof Function)) {
            return cc.error("Timer.callLater method is not a function");
        }
        
        let _uuid = uuid ? uuid : Timer.newId;
        let _eventType = idleTime ? cc.Director.EVENT_AFTER_UPDATE : cc.Director.EVENT_BEFORE_UPDATE;
        let _event 
       
        uuid && this.clearCallLater(_uuid);  // 同一帧内同个uuid多次调用, 只会执行一次
        let _method = () => 
        {
            // idleTime && console.log("延迟执行间隔时间", dt,dt < idleTime, "ms")
            if(!idleTime || Timer.frameDt < idleTime){
                // idleTime: 等到空闲帧后再调用
                this.callLaterEvents.delete(_uuid);
                cc.director.off(_eventType, _method, caller);
                method.call(caller);
            }
        };
        _event = {eventType: _eventType, caller, method, sourceMethod: _method };
        this.callLaterEvents.set(_uuid, _event);

        cc.director.on(_eventType, _method, caller);
    }

    static clearAll(target: any) {
        // 清除定时器
        if (target['_id'] != null || target['__instanceId'] != null) {
            cc.director.getScheduler().unscheduleAllForTarget(target);
        }
        // 清除延迟调用
        for (const iterator of this.callLaterEvents.entries()) {
            let event = iterator[1];
            if(event.caller == target){
                this.callLaterEvents.delete(iterator[0]);
                cc.director.off(event.eventType, event.sourceMethod,  event.caller);
            }
        }
    }

    static clear(target: any, method: Function) {
        if (target['_id'] != null || target['__instanceId'] != null) {
            cc.director.getScheduler().unschedule(method, target);
        }
    }

    static clearCallLater(uuid: number | string) {
        if(this.callLaterEvents.has(uuid)){
            let event = this.callLaterEvents.get(uuid);
            this.callLaterEvents.delete(uuid);
            cc.director.off(event.eventType, event.caller, event.sourceMethod);
        }
    }
    
    /**
     * 定时重复执行(基于帧率)。
     * @param fps 间隔几帧(单位为帧)。
     * @param caller 执行域(this)。
     * @param method 定时器回调函数。
     * @param args 回调参数。
     */
    static frameLoop(fps: number, caller: any, method: Function, args?: any[]): void{
        let t = 1 / cc.game.getFrameRate() * 1000;
        Timer.loop(fps * t - 3, caller, method, args);
    }
    
    /**
     * 定时重复执行。
     * @param delay 间隔时间(单位毫秒)。
     * @param caller 执行域(this)。
     * @param method 定时器回调函数。
     * @param args 回调参数。
     */
    static loop(delay: number, caller: any, method: Function, args?: any[]): void {
        cc.director.getScheduler().enableForTarget(caller);
        cc.director.getScheduler().schedule(method, caller, delay / 1000, cc.macro.REPEAT_FOREVER, 0, false);
    }


    /**
    * 定时重复执行。
    * @param delay 间隔时间(单位毫秒)。
    * @param caller 执行域(this)。
    * @param method 定时器回调函数。
    * @param times 执行次数
    * @param args 回调参数。
    */
    static loop1(delay: number, caller: any, method: Function, times: number, args?: any[]): void {
        if(times === 0) return
        cc.director.getScheduler().enableForTarget(caller);
        cc.director.getScheduler().schedule(method, caller, delay / 1000, times - 1, 0, false);
    }



    /**
     * 定时执行一次。
     * @param delay 延迟时间(单位为毫秒)。
     * @param caller 执行域(this)。
     * @param method 定时器回调函数。
     * @param args 回调参数。
     */
    static once(delay: number, caller: any, method: Function): void {
        cc.director.getScheduler().enableForTarget(caller);
        cc.director.getScheduler().schedule(method, caller, delay / 1000, 0, 0, false);
    }

    /**
     * 定时器生命周期跟随Node
     * @param dt 延迟时间(单位为毫秒)
     * @param node 
     * @param method 
     * @returns 
     */
    static delayCallback(dt: number, node: cc.Node, method: Function) {
        return cc.tween(node).delay(dt/1000).call(method).start();
    }

    /**
     * @param caller 执行域(this)。
     * @param idleTime 等到空闲帧后再调用,单位毫秒。1000ms, 在 idleTime 时间内代表空闲帧
     * @returns 
     */
    static waitAsync(caller: any, idleTime?: number){
        return new Promise((resolve,reject)=>{
            this.callLater(caller, resolve, idleTime)
        })
    }
}
