const {ccclass, property} = cc._decorator;

/** 滚动列表item控制器 */
@ccclass
export default class ScrollItemCtrl extends cc.Component {

    @property(cc.ScrollView)
    scrollView: cc.ScrollView = null;

    private maskNode: cc.Node = null;
    private content: cc.Node = null;
    private clampSize: number = 0;
    private itemOpacity: number = 0;

    start () {
        if(!this.scrollView) {
            this.scrollView = this.getComponent(cc.ScrollView);
        }
        if(this.scrollView && !(this.scrollView.horizontal && this.scrollView.vertical)) {
            this.scheduleOnce(()=>{
                this.init();
            })
        }
    }

    public init(){
        this.maskNode = this.scrollView.content.parent;
        this.content = this.scrollView.content;
        if(this.content.children.length > 0){
            this.scrollView.node.on('scrolling', this.onScrollEnd, this);
            this.itemOpacity = this.content.children[0].opacity;
            if(this.scrollView.horizontal){
                this.clampSize = this.maskNode.width / 2 + this.content.children[0].width * 2;
            }
            else{
                this.clampSize = this.maskNode.height / 2 + this.content.children[0].height * 2;
            }
            this.onScrollEnd();
        }
        else{
            console.info('ScrollItemCtrl: content is empty');
        }
    }

    onScrollEnd() {
        if(this.scrollView.horizontal){
            for(let i = 0; i < this.content.children.length; i++) {
                let item = this.content.children[i];
                let itemPos = item.changeV2Pos(this.maskNode);
                if(Math.abs(itemPos.x) > this.clampSize){
                    if(item.opacity !== 0){
                        item.opacity = 0;
                    }
                }
                else{
                    if(item.opacity !== this.itemOpacity){
                        item.opacity = this.itemOpacity;
                    }
                }
            }
        }
        else{
            for(let i = 0; i < this.content.children.length; i++) {
                let item = this.content.children[i];
                let itemPos = item.changeV2Pos(this.maskNode);
                if(Math.abs(itemPos.y) > this.clampSize){
                    if(item.opacity !== 0){
                        item.opacity = 0;
                    }
                }
                else{
                    if(item.opacity !== this.itemOpacity){
                        item.opacity = this.itemOpacity;
                    }
                }
            }
        }
    }

    public onScrollStart() {
        for(let i = 0; i < this.content.children.length; i++) {
            this.content.children[i].opacity = 255;
        }
    }
}
