import { Logger } from "../engine/Logger";

export function Once(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const originalMethod = descriptor.value;

  descriptor.value = function (...args: any[]) {
    if (!this[propertyKey + "_executed"]) {
      this[propertyKey + "_executed"] = true;
      return originalMethod.apply(this, args);
    } else {
      Logger.log(`Method ${propertyKey + "_executed"} has already been executed on this instance.`);
    }
  };

  return descriptor;
}

export function OnPropertyChange(target, key, changeHandle: Function) {
  let value = target[key];
  Object.defineProperty(target, key, {
    get() {
      return value;
    },
    set(newValue) {
      if (value !== newValue) {
        value = newValue;
        changeHandle && changeHandle();
        console.log(`Property '${key}' modified:`, newValue);
      }
    },
    enumerable: true,
    configurable: true
  });
}

export function OffPropertyChange(target, key) {
  // 重新定义属性的 get 和 set 方法
  const descriptor = Object.getOwnPropertyDescriptor(target, key);
  target[key] = null;
  Object.defineProperty(target, key, {
    get: null, // 保留原始的 get 方法
    set: null
  });
}