    // 安全检查
    static s_file : Map<string , {m : string , data : any}> = new Map<string , {m : string , data : any}>();
    static s_data : any;
    static exception_heart_count : number = 0;  //异常次数
    static exception_speed : number;        //异常变速
    static CheckSafeFile(){
        if(PlatformManager.Is_IOS) return;  //苹果手机不检查，无论小程序或者APP
        // 安全检查
        let _keys = SingletonAttribute.s_file.keys();
        let _m : string;
        let _d : {m : string , data : any};
        for(let _k of _keys){
            _d = SingletonAttribute.s_file.get(_k);
            _m = Md5Helper.getMd5Default(JSON.stringify(_d.data));
            if(_m != _d.m){
                // 作弊
                !this.s_data && (this.s_data = {});
                this.s_data[_k] = {orgin : _d.m , now : _m};
                console.error("作弊 "+_k+"  原来MD5 "+_d.m+" 修改后MD5" + _m);
            }
        }
    }
    

