import Loader from "../../../System/Loader";
import { UserDataMgr } from "../../../System/User/UserDataMgr";
import UIManager from "../../../System/ui/UIManager";
import { UI_Cache_Type, UI_Config, ViewConfig } from "../../../System/ui/UI_Config";
import Tools from "../../../Tools/Tools";
import ComponentBase from "../../../engine/ComponentBase";
import ResourcesManager from "../../../engine/ResourceManager";
import { GameMode, ILevelData } from "../../../gamePlaySystem/GameAttribute";
import { BasicGameManger } from "../../../gamePlaySystem/GameManager/BasicGameManger";
import BundleMgr from "../../BundleMgr";
import GameData from "../../GameData";
import UIData from "../../fgui/GameUIEnum";

const { ccclass, property } = cc._decorator;

@ccclass
export default class Item_leveEntrance extends ComponentBase {
    Label_lv: cc.Label;
    private icon: cc.Sprite;
    private loader: Loader;
    lock: cc.Node;
    isPassNode: cc.Node;
    _data: ILevelData;
    label_title: cc.Label;

    onLoad() {
        let a = 0
        // this.loader = new Loader();
        this.onAddEvent(this.node, () => { this.OnClick() })
    }

    Init() {
        this.BindUi();
        return this;
    }

    BindUi() {
        this.icon = this.getChild(this.node, "icon", cc.Sprite);
        this.lock = this.getChild(this.node, "lock", cc.Node);
        this.isPassNode = this.getChild(this.node, "isPass", cc.Node);
        this.Label_lv = this.getChild(this.node, "Label_lv", cc.Label);
        this.label_title = this.getChild(this.node, "label_title", cc.Label);

        // this.Label_lv.node.active = CC_DEBUG;
    }

    private _gameMode: GameMode;

    SetData(data: ILevelData, gameMode: GameMode) {
        this._data = data;
        this._gameMode = gameMode;

        this.Label_lv.string = this._data.level + "";
        this.label_title.string = this._data.title;
        // this.loader.loadSprite()
        ResourcesManager.instance.loadSprite(this.icon, new UI_Config(UIData.GetLvIcon(data.icon), UI_Cache_Type.someTimes, true, BundleMgr.bundles.resources));
        this.lock.active = !UserDataMgr.instance.isUnLock(data.level, gameMode) && Tools.GetQueryString('unlock') == null;
        this.isPassNode.active = UserDataMgr.instance.isPassedLevel(data.level, gameMode);
        return this;
    }

    ReflashView(){
        this.SetData(this._data, this._gameMode);
    }

    OnUnlock(){
        UIManager.instance.showView(ViewConfig.UnlockView, (view)=>{}, this._data.level, this._gameMode);
    }

    OnClick() {
        if(this.lock.active) return this.OnUnlock();   

        this.node.getComponent(cc.Button).interactable = false;
        UIManager.instance.showLoadingIcon();
        //进入对应关卡
        GameData.gotoLevel(this._data.level, this._gameMode,()=>{
            //成功进入
            UIManager.instance.hideLoadingIcon();
            UIManager.instance.closeViewByConfig(ViewConfig.HomeView);
            this.node.getComponent(cc.Button).interactable = true;
        });
    }
}
