import { EngineConfig } from "./EngineConfig";

export const enum LOG_LEVEL_TYPES { DEBUG, LOG, INFO, WARN, ERROR }
const Log_Level_Names: Array<string> = ["debug", "log", "info", "warn", "error"];

export class Logger {
    // public static tag: string = "[HaoJslog]"; //可以设置当前游戏的前缀
    private static level: number = LOG_LEVEL_TYPES.DEBUG; //当前Logger等级

    //当前Logger等级
    public static get LEVEL() {
        return this.level;
    }
    public static set LEVEL(v) {
        this.level = v;
        cc.game.config && (cc.game.config.debugMode = v);

        LOG_LEVEL_TYPES.DEBUG < v && (this.debug = console.debug = () => { });
        LOG_LEVEL_TYPES.LOG < v && (this.log = console.log = () => { });
        LOG_LEVEL_TYPES.INFO < v && (this.info = console.info = () => { });
        LOG_LEVEL_TYPES.WARN < v && (this.warn = console.warn = () => { });
        LOG_LEVEL_TYPES.ERROR < v && (this.error = console.error = () => { });
    }

    static get IsDebugLog() {
        return this.LEVEL == LOG_LEVEL_TYPES.DEBUG;
    }

    public static isPrintTime: boolean = false; //当前Logger等级

    public static Log_Color_Config: Array<string> = [
        "color:#890;font-size:10px;",
        "color:#000;font-size:11px;",
        "color:#09f;font-size:12px;",
        "color:#f90;font-size:13px;",
        "color:#f00;font-size:15px;",
    ];

    private static Terminal_Log: boolean = false;

    public static formatNow() {
        let date: Date = new Date(); //后端返回的时间戳是秒
        return date.getFullYear() + "-" + (date.getMonth() + 1) + "-" + date.getDate() + " " + date.getHours() + ":" + date.getMinutes() + ":" + date.getSeconds() + ":" + date.getMilliseconds();
    }

    private static getLogPreKey(nowLevel: number): string {
        let str: string = Logger.isPrintTime ? "[" + Logger.formatNow() + "] " : "";
        return str;
    }
    
    public static Init(){
        if(CC_DEBUG){
            Logger.LEVEL = LOG_LEVEL_TYPES.DEBUG;
            return;
        }
        if (CC_JSB || !cc.sys.isNative && (EngineConfig.environment == EngineConfig.EnvironmentType.Online || EngineConfig.environment == EngineConfig.EnvironmentType.Test || cc.sys.isMobile) ) {
            Logger.LEVEL = LOG_LEVEL_TYPES.WARN;
        } else {
            if (EngineConfig.environment == EngineConfig.EnvironmentType.Online || EngineConfig.environment == EngineConfig.EnvironmentType.Test || cc.sys.isMobile) {
                Logger.LEVEL = LOG_LEVEL_TYPES.WARN;
            } else {
                Logger.LEVEL = LOG_LEVEL_TYPES.DEBUG;
            }

        }
        this.error("Logger.LEVEL: ", Logger.LEVEL);
    }

    private static _log = console.log;
    public static debug = console.debug;
    public static log = console.log;
    public static info = console.info;

    public static warn(...args) {
        if (Logger.LEVEL > LOG_LEVEL_TYPES.WARN) {
            return;
        }
        console.warn(...arguments)
    }

    public static error(...args) {
        if (Logger.LEVEL > LOG_LEVEL_TYPES.ERROR) {
            return;
        }
        console.error(...arguments)
    }

    /**
     * 设置忽略的 log head 
     * @param ignoreHead 
     */
    public static setIgnores(ignoreHead: any[]) {
        if (ignoreHead.length) {
            let map = {};
            ignoreHead.forEach((v) => {
                map[v] = true;
            });
            let log = this._log;
            this.log = console.log = (...args) => {
                if (map[args[0]]) {
                    return;
                }
                log(...args);
            }
        }
    }
}

if (!CC_EDITOR) {
    cc.error = (str, ...params) => {
        if (str instanceof String && str.includes("Sorry, ")) {
            console.log(str);
            return;
        }
        console.error(str, ...params);
    }
}
if(CC_DEBUG) window['Logger'] = Logger;

// 兼容laya项目
export const Debug = Logger;