import BasePlatformAPI from "./BasePlatformAPI";

export default class OpenAPI extends BasePlatformAPI {

    private static user : OpenAPI = null;
    public static get Init() : OpenAPI{
      if(this.user == null){
        this.user = new OpenAPI();
      }
      return this.user;
    }

    private userinfobtn;

    /** 配置授权按钮 */
    public CreateUserInfoButton(left : number , top : number , width : number , height : number) : Promise<any>{
        if(!this.api) return;
        let _size = cc.view.getVisibleSize();
        let wp = this.api.getSystemInfoSync().screenWidth / _size.width;
        let hp = this.api.getSystemInfoSync().screenHeight / _size.height;
        let bottonstyle =  {
            type : 'text',
            text : '',
            style:{
                left : left * wp,
                top : top * hp,
                width : width * wp,
                height : height * hp
            }
        }        
        return new Promise((resolve, reject) => {
            if (bottonstyle == null) {
              resolve(null);
            }
            this.userinfobtn = this.api.createUserInfoButton(bottonstyle);
            this.userinfobtn.onTap(res => {
                this.userinfobtn.hide(); //console.log(res);
                resolve(res);
            });
        });
    }

    /** 显示授权按钮 */
    public ShowUserInfoButton(){
        if(!this.userinfobtn) return;
        this.userinfobtn.show();
    }

    /** 隐藏授权按钮 */
    public HideUserInfoButton(){
        if(!this.userinfobtn) return;
        this.userinfobtn.hide();
    }

    /** 登录 */
    public WXLogin() : Promise<{errMsg : string , code : string}>{
        if(!this.api) return new Promise((r , j)=>{
            j();
        });
        return new Promise((r, j) => {
            //console.log("login");  
            this.api.login({
              success: res => {
                r(res);
              },
              fail: res => {
                console.log(res);
                this.WXLogin();
              }
            });
        });
    }

    /** 检查登录是否过期 */
    public CheckSession() : Promise<boolean>{
        if(!this.api) return new Promise((r , j)=>{
            j();
        });       
        return new Promise((r, j) => {
            this.api.checkSession({
              success() {
                r(true);
              },      
              fail() {
                j(false);
              }      
            });
        });
    }

    /**获取用户的当前设置。返回值中只会出现小程序已经向用户请求过的权限 
    * https://developers.weixin.qq.com/minigame/dev/api/open-api/user-info/wx.getSetting.html
    */
     public GetSetting(){
        if(!this.api) return new Promise((r , j)=>{
            j();
        }); 
        return new Promise((r, j) => {
            this.api.getSetting({
              success: res => {                
                r(res);
              },
              fail: res => {
                j(res);
              }
            });
        });
    }

    /**授权 */
    public GetUserInfo() : Promise<any>{
        if(!this.api) return new Promise((r , j)=>{
            j();
        }); 
        return new Promise((resolve, reject) => {
            this.api.getUserInfo({
              success: res => {
                //console.log(res);
                resolve(res);
              },
              fail: res => {
                resolve(null);
              }
            });
        });
    }

    /**
     * 根据用户当天游戏时间判断用户是否需要休息
     * @param todayplaytime 今天已经玩游戏的时间，单位：秒
     */
     public CheckIsUserAdvisedToRest(todayplaytime : number){
        if(!this.api) return;
        return new Promise((resolve, reject) => {
            this.api.checkIsUserAdvisedToRest({
              todayPlayedTime: todayplaytime,
              success: res => {
                resolve(res);
              },
              fail: res => {
                resolve(res);
              }
            });
        });
    }

    /** 
     * 抖音侧边栏接口: 
     * https://developer.open-douyin.com/docs/resource/zh-CN/mini-game/operation1/ability/-retention/sidebar
     */
    public ShowRevisitGuide(){
      if(!this.api || !this.api.showRevisitGuide) return;
      return new Promise((resolve, reject) => {
        this.api.showRevisitGuide({
          success: res => {
            console.log(res);
            resolve(res);
          },
          fail: res => {
            reject(res);
          }
        });
      });
    }
}