import { AndroidHelper } from "../sdk/AndroidHelper";
import { IOSHelper } from "../sdk/IOSHelper";
import DeviceAPI from "../wx_api/DeviceAPI";

export default class JSB_Vibrate {

    /** 提示 */
    public static init(){
        DeviceAPI.Init.VibrateLong = function () {
            if(CC_JSB){
                if(cc.sys.os == "Android"){
                    AndroidHelper.VibrateLong();
                }else if(cc.sys.os == "iOS"){
                    IOSHelper.VibrateLong();
                }
            }
        };

        DeviceAPI.Init.VibrateShort = function () {
            if(CC_JSB){
                if(cc.sys.os == "Android"){
                    AndroidHelper.VibrateShort();
                }else if(cc.sys.os == "iOS"){
                    IOSHelper.VibrateShort();
                }
            }
        };
    }
}