import BaseStorageValue from "./BaseStorageValue";

/**
 * 字符串类型保存
 */
export default class StringStorageValue extends BaseStorageValue<string> {

    set SetValue(value : string){
        this.change = true;
        this.value = value;
    };
    get GetValue(): string {
        return this.value;
    }
    public constructor(key : string , value : string , monitor : boolean = true){
        super(key , value , monitor);
    }

    Save(_force : boolean = false) : any {        
        if(this.change || _force){
            this.change = false;
            return this.value;
        }
        return null;
    }
    Load(value: any): string {
        if(value == undefined || !value) return;
        this.value = String(value);
        this.change = true;
    }
}