import { UserDataMgr } from "./System/User/UserDataMgr";
import ResourcesManager from "./engine/ResourceManager";
import BundleMgr from "./game/BundleMgr";
import { GameMode, ILevelData, IsettingJson } from "./gamePlaySystem/GameAttribute";

export class GameJsonConfig {
    private static _settingJson: IsettingJson = <any>{};
    public static get json_setting(){
        return this._settingJson;
    }

    public static json_setting_lv: {[key: string]: {[key: number]: ILevelData}} = <any>{};

    /** 获取当前游戏模式的关卡数据 */
    public static getCurrentLevelDatas(gameMode?: GameMode): ILevelData[] {
        if (!gameMode) {
            gameMode = UserDataMgr.instance.GetSelectedGameMode() as GameMode;
        }
        
        // 优先使用levelInfo，如果不存在则使用datas（向后兼容）
        if (this._settingJson.levelInfo && this._settingJson.levelInfo[gameMode]) {
            return this._settingJson.levelInfo[gameMode];
        }
        return this._settingJson.datas || [];
    }

    public static Necessary(){
        this._settingJson = ResourcesManager.instance.getResByBundleNameAndPath(BundleMgr.bundles.setting, "setting", cc.JsonAsset).json;
        
        // 初始化所有游戏模式的关卡数据
        // 遍历所有游戏模式
        const gameModes = [GameMode.NDRG, GameMode.JQPT, GameMode.KPQQ, GameMode.ZBT];
        gameModes.forEach(mode => {
            const datas = this._settingJson.levelInfo[mode];
            if (datas) {
                // 初始化游戏模式的关卡数据对象
                if (!this.json_setting_lv[mode]) {
                    this.json_setting_lv[mode] = {};
                }
                let next_unlook = false;
                for(let i = 0, len = datas.length; i < len; i++){
                    let data = datas[i];
                    this.json_setting_lv[mode][data.level] = data;
                    if(next_unlook && !UserDataMgr.instance.isUnLock(data.level, mode)){
                        UserDataMgr.instance.SaveLevelLock(data.level, true, false, mode);
                        console.warn("上一关已通关, 自动解锁当前关卡:", data.level)
                    }
                    next_unlook = UserDataMgr.instance.isPassedLevel(data.level, mode);
                }
            }
        });
    }

    /** 获得下一关 */
    public static getNextLevel(curLv: number, gameMode?: GameMode): number | null {
        const datas = this.getCurrentLevelDatas(gameMode);
        let idx = datas.findIndex(data => data.level == curLv) + 1;
        for (let i = idx; i < datas.length; i++) {
            const data = datas[i];
            if(data.level != -1){
                return data.level;
            }
        }
        return null;
    }

    public static GetIndex(curLv: number, gameMode?: GameMode): number {
        const datas = this.getCurrentLevelDatas(gameMode);
        return datas.findIndex(data => data.level == curLv);
    }
    
    public static hasNextLevel(curLv: number, gameMode?: GameMode): boolean {
        return this.getNextLevel(curLv, gameMode) != null;
    }
}