import { Logger } from "../engine/Logger";

/** 监听缓存池node意外释放位置 */
export default class CheckNodeDestroy extends cc.Component {
    
    onDestroy() {
        Logger.error("释放了需要回收的对象!!!, 当前NodeTree路径:", this.getPath(this.node));
    }

    getPath(node: cc.Node): string {
        let path = node.name;
        while (node.parent) {
            path = node.parent.name + "/" + path;
            node = node.parent;
        }
        return path;
    }
   
}