
export const CPoints : CPoint[] = [];

export default class CPoint {

    x : number;
    y : number;

    static create() : CPoint{
        if(CPoints.length > 0){
            return CPoints.pop();
        }else{
            return new CPoint();
        }
        // return CPoints.length > 0 ? CPoints.shift() : new CPoint();
    }

    public reset(){
        this.x = 0;
        this.y = 0;
        return this;
    }

    public recover(){
        this.reset();
        CPoints.push(this);
    }

    public setTo(x : number , y : number){
        this.x = x;
        this.y = y;
        return this;
    }

    public distance(x : number = 0, y : number = 0) {
        return Math.sqrt((this.x - x) * (this.x - x) + (this.y - y) * (this.y - y));
    }

    public lengthPow2(): number {
        return this.x * this.x + this.y * this.y;
    }

    public normalize(){
        var d = Math.sqrt(this.x * this.x + this.y * this.y);
        if (d > 0) {
            var id = 1.0 / d;
            this.x = Math.round(this.x * id * 10000) / 10000;
            this.y = Math.round(this.y * id * 10000) / 10000;
        }
        return this;
    }

    public copy(point : CPoint) {
        return this.setTo(point.x, point.y);
    }

    // public get module(){
    //     var d = Math.sqrt(this.x * this.x + this.y * this.y);
    //     return d;
    // }
}