import { GameJsonConfig } from "../../../GameJsonConfig";
import { GameEvent } from "../../../System/GameEvent/GameEvent";
import ViewBase from "../../../engine/ViewBase";
import { GameMode, IsettingJson } from "../../../gamePlaySystem/GameAttribute";
import { BasicGameManger } from "../../../gamePlaySystem/GameManager/BasicGameManger";
import Singleton from "../../../singleton/Singleton";
import PageCom from "./PageCom";
import Timer from "../../../Tools/Timer";
import { UserDataMgr } from "../../../System/User/UserDataMgr";
import { ViewConfig } from "../../../System/ui/UI_Config";
import UIManager from "../../../System/ui/UIManager";
import GameData from "../../GameData";


const { ccclass, property } = cc._decorator;

@ccclass
export default class LevelPageView extends ViewBase {

	@property({ type: dragonBones.ArmatureDisplay, displayName:'' })
	mySke: dragonBones.ArmatureDisplay = null;

    private pageView: cc.PageView = null;
    private pageNode: cc.Node = null;
    private Label_level: cc.Label;
    gamesPanel: cc.Node;
    // private adTimeout: cc.Label;


    onLoad(): void {
        // this.adTimeout = this.getChild(this.node, "adTimeout", cc.Label);
        this.pageView = this.getChild(this.node, "PageView", cc.PageView);
        this.pageNode = this.getChild(this.node, "myPage");
        this.gamesPanel = this.getChild(this.node, "gamesPanel") as cc.Node;

		this.onAddEvent(this.getChild(this.node, "PageView/left"), () => { this.onClick_leftBtn() });
		this.onAddEvent(this.getChild(this.node, "PageView/right"), () => { this.onClick_rightBtn() });
		this.onAddEvent(this.getChild(this.node, "topPanel/settingBtn"), () => { this.onClick_SettingBtn() });
		this.Label_level = this.getChild(this.node, "PageView/Label_level").getComponent(cc.Label);
        this.initGamesBtn();
    }

    /** 选择游戏类型，更新对应关卡列表 */
    initGamesBtn(){
        this.gamesPanel.children.forEach((node)=>{
            node.on(cc.Node.EventType.TOUCH_END, ()=>{
                this.selectGamesBtn(node.name as GameMode);
            })
        }) 
        
        // 默认选择第一个模式或从用户数据读取
        let defaultMode = (UserDataMgr.instance.GetSelectedGameMode() || this.gamesPanel.children[0].name) as GameMode;
        this.selectGamesBtn(defaultMode);
    }
    
    private lastSelectNode: cc.Node = null;
    /** 突出选中的游戏类型 */
    selectGamesBtn(gameMode: GameMode) {
        if (this.lastSelectNode && this.lastSelectNode.name === gameMode) {
            return;
        }
        let selectFunc = (node: cc.Node, isSeleced: boolean)=>{
            node.stopAllActions();
            node.getChildByName('label').color = isSeleced ? cc.color(93, 0, 200) : cc.color(132, 46, 0);
            node.getChildByName('bg2').active = isSeleced;
            node.getChildByName('bg1').active = !isSeleced;
            cc.tween(node)
                .to(0.1, isSeleced ? 
                    { scale: 1.1, y: 15 } : 
                    { scale: 1, y: 0 }, 
                    { easing: 'sineOut' })
                .call(() => {
                })
                .start();
        } 
        let selectedNode = this.gamesPanel.getChildByName(gameMode);
        // 恢复上一个节点缩放
        this.lastSelectNode && selectFunc(this.lastSelectNode, false)
        this.lastSelectNode = selectedNode;
        // 放大当前节点
        selectFunc(selectedNode, true);
        
        // 记录到用户数据管理类
        UserDataMgr.instance.SetSelectedGameMode(gameMode);
        this.currentGameMode = gameMode;
        this.ReflashLvList();
    }


    private _pageCount: number;
    private currentPageIndex: number = 0;
    private currentGameMode: GameMode = null;
    start() {
        this.pageView.node.on("scroll-ended", this.onScrollEnded, this);
        this.ReflashPageLabel();
    }

    onInitChild() {
        if (this.isInit) {
            this.pageView.getComponentsInChildren(PageCom).forEach(v=>v.RefashPageView())
        }
        // 广告解锁关卡时刷新页面
        Singleton.GameEventSystem.on(GameEvent.UP_HOME_UI, this, () => {
            this.pageView.getComponentsInChildren(PageCom).forEach(v=>v.RefashPageView())
        })
        Singleton.SoundSystem.PlayBgm('resources',"sound/home_bgm");
    }

	onEnable(){
		// Timer.loop(1000, this, ()=>{
		// 	let unlockTime = UserDataMgr.instance.GetUnlockTime();
		// 	if(!unlockTime){
		// 		// this.adTimeout.node.active = false;
		// 		return;
		// 	}
        //     // 剩余时间
        //     let time = unlockTime - Date.now();
		// 	// this.adTimeout.node.active = true;
        //     // 倒计时: 24:00:00
		// 	// this.adTimeout.string = `解锁倒计时: ${DateUtil.formatHourMinSecondStr(time + 57600000)}`;
		// })
	}

    onDisable(): void {
        Singleton.GameEventSystem.clear(this);
        Timer.clearAll(this);
    }

    /** 用于跟踪已加载页面的索引和节点。 */
    private loadedPages: Map<number, cc.Node> = new Map();
    /** 用于缓存被移除的页面节点，避免频繁创建/销毁。 */
    private pagePool: Map<number, cc.Node> = new Map();
    /** 记录上次已加载的当前页索引，防止重复刷新。 */
    private lastLoadedIndex: number = -1;

    /** 刷新关卡列表 */
    ReflashLvList() {
        // 清除所有已加载的页面（先移除，再放到暂存池）
        this.pageView.removeAllPages();
        this.loadedPages.forEach((node, index) => { node.destroy(); });
        this.loadedPages.clear();
        this.pagePool.forEach((node, index) => { node.destroy(); });
        this.pagePool.clear();
        this.lastLoadedIndex = -1;

        let datas = GameJsonConfig.getCurrentLevelDatas(this.currentGameMode).filter(v => v.level != -1);
        this._pageCount = Math.ceil(datas.length / 6);
        this.currentPageIndex = 0;
        // 加载当前页及其邻页
        this.updateLoadedPages(0);
    }

    private loadPage(index: number) {
        if (this.loadedPages.has(index)) return;

        let datas = GameJsonConfig.getCurrentLevelDatas(this.currentGameMode).filter(v => v.level != -1);
        let _datas = datas.slice(6 * index, 6 * (index + 1));
        if (_datas.length === 0) return;

        // 优先从暂存池取页面
        let pageNode = this.pagePool.get(index);
        if (pageNode) {
            this.pagePool.delete(index);
            pageNode.active = true;
            pageNode.name = `${index}`;
            this.pageView.addPage(pageNode);
            pageNode.getComponent(PageCom).RefashPageView()//SetData(_datas, index);
            this.loadedPages.set(index, pageNode);
            return;
        }

        // 直接创建新页面
        let newP = cc.instantiate(this.pageNode);
        newP.name = `${index}`;
        this.pageView.addPage(newP);
        newP.addComponent(PageCom);
        newP.active = true;
        newP.getComponent(PageCom).SetData(_datas, index, this.currentGameMode);
        this.loadedPages.set(index, newP);
    }

    private unloadPage(index: number) {
        if (!this.loadedPages.has(index)) return;
        let node = this.loadedPages.get(index);
        this.pageView.removePage(node);
        node.active = false;
        this.pagePool.set(index, node);
        this.loadedPages.delete(index);
    }

    private updateLoadedPages(currentIndex: number) {
        // 避免重复刷新同一页面（例如重复触发 scroll-ended）
        if (this.lastLoadedIndex === currentIndex) return;
        this.lastLoadedIndex = currentIndex;

        // 先移除所有当前加载的页面到缓存池，防止顺序混乱
        this.loadedPages.forEach((node, index) => {
            this.pageView.removePage(node);
            node.active = false;
            this.pagePool.set(index, node);
        });
        this.loadedPages.clear();

        // 重新加载需要的页面（左、中、右）
        let pagesToLoad = [currentIndex - 1, currentIndex, currentIndex + 1].filter(i => i >= 0 && i < this._pageCount);
        pagesToLoad.forEach(i => this.loadPage(i));

        // 设置透明度：只显示加载的页面
        this.pageView.content.children.forEach(child => {
            child.opacity = 0;
        });
        pagesToLoad.forEach(i => {
            if (this.loadedPages.has(i)) {
                this.loadedPages.get(i).opacity = 255;
            }
        });

        // 设置 PageView 的当前页面为中间的页面（索引1）
        let idx = currentIndex === 0 ? 0 : 1;
        // console.warn(`设置当前页面索引为 ${idx}，对应实际页面索引 ${currentIndex}`);
        this.pageView.scrollToPage(idx, 0);
        this.ReflashPageLabel();
    }

    onScrollEnded(_) {
        const oldIndex = this.currentPageIndex;
        let pageIndex = this.pageView.getCurrentPageIndex();
        if (pageIndex === 0 && oldIndex > 0) {
            this.currentPageIndex = oldIndex - 1;
        } else if (pageIndex === 2 && oldIndex < this._pageCount - 1) {
            this.currentPageIndex = oldIndex + 1;
        } else if (pageIndex === 1 && oldIndex == 0) {
            // 从第一页向右滚动
            this.currentPageIndex ++;
        } else {
            return;
        }
        this.updateLoadedPages(this.currentPageIndex);
    }

    ReflashPageLabel() {
        this.Label_level.string = (this.currentPageIndex + 1) + "/" + this._pageCount;
    }

    private onClick_leftBtn() {
        if (this.currentPageIndex > 0) {
            this.currentPageIndex--;
            this.updateLoadedPages(this.currentPageIndex);
        }
    }

    private onClick_rightBtn() {
        if (this.currentPageIndex < this._pageCount - 1) {
            this.currentPageIndex++;
            this.updateLoadedPages(this.currentPageIndex);
        }
    }

    playGmae(_, level: number) {
        GameData.gotoLevel(level, this.currentGameMode, () => {
            this.closeView();
        })
    }

    private onClick_SettingBtn() {
        UIManager.instance.showView(ViewConfig.SettingView);
    }
}
