import FGUIManager from "../System/Fgui/FGUIManager";
import {GameEvent} from "../System/GameEvent/GameEvent";
import {SettingManager} from "../System/Setting/SettingManager";
import {SoundManager} from "../System/Sound/SoundManager";
import {UserManager} from "../System/User/UserManager";
import {VideoAdManager} from "../System/VideoAd/VideoAdManager";

export const Version: string = "1.0.0";

export default class Singleton {
  /** 用户服务器共用数据 */
  static UserSystem: UserManager;
  /** 广告 */
  static VideoAdSystem: VideoAdManager;
  /** 设置 */
  static SettingSystem: SettingManager;
  /** 声音 */
  static SoundSystem: SoundManager;

  private static CleanData_BaseGameSystem() {
    this.UserSystem.ClearData();
    this.SettingSystem.ClearData();
    this.SoundSystem.ClearData(); //抖音版本说切换人物后，声音设置没有保留，所以这里不清空了
  }
  //#endregion

  static GameEventSystem: GameEvent;

  static CleanData() {
    this.CleanData_BaseGameSystem();
  }
}

if (CC_DEBUG) {
  window["__Singleton__"] = Singleton;
}
