
const space = 2;

type AtlasFrame = {
    rect: cc.Rect;
    texture: cc.RenderTexture;
    id: string;
    name: string;
}

export class DynamicAtlas {
    private _texture: cc.RenderTexture;
    private _x: number;
    private _y: number;
    private _nexty: number;
    private _width: number;
    private _height: number;
    private _innerTextureInfos: {};
    private _count: number;
    private _dirty: boolean;
    private _spriteFrames: Map<string, cc.SpriteFrame> ;
	public get texture(){
		return this._texture;
	}
    
    /**
     * 初始化图集大小，默认2048*2048
     * @param width 
     * @param height 
     */
	constructor(width: number = 2048, height: number = 2048) {
        let texture = new cc.RenderTexture;
        texture.initWithSize(width, height);
        //@ts-ignore
        texture.update();
        
        this._texture = texture;

        this._x = space;
        this._y = space;
        this._nexty = space;

        this._width = width;
        this._height = height;

        this._innerTextureInfos = {};
        this._spriteFrames = new Map()

        this._count = 0;
    }
    
    /**
     * 将 Sprite.spriteFrame 添加到动态图集中并替换为图集的 SpriteFrame
     * @example atlas.covertSpriteFrameToAtlas(node.getComponent(cc.Sprite))
     * @param sprite 
     */
    covertSpriteFrameToAtlas (sprite: cc.Sprite): boolean {
        let frame = this.insertSpriteFrame(sprite.spriteFrame);
		if (frame){
            let spriteFrame = this.getSpriteFrame(frame)
			sprite.spriteFrame = spriteFrame
			return true
		}else{
			console.warn("图集已满:装不下",frame.name)
			return false
		}
    }

    /**
     * 获得图集中的 SpriteFrame
     * @param frame 
     * @returns
     */
    getSpriteFrame (frame: AtlasFrame) {
        if (this._spriteFrames.has(frame.id)) {
            return this._spriteFrames.get(frame.id);
        }
        
        let spriteFrame = new cc.SpriteFrame()
        spriteFrame.setTexture(frame.texture, frame.rect);
        this._spriteFrames.set(frame.id, spriteFrame);
        return spriteFrame
    }
    
    /**
     * 将 SpriteFrame 添加到动态图集中
     * @param spriteFrame 
     * @returns 
     */
    insertSpriteFrame (spriteFrame: cc.SpriteFrame): AtlasFrame {
        // @ts-ignore
        let rect = spriteFrame._rect
        // @ts-ignore
        let texture = spriteFrame._texture
        let info = this._innerTextureInfos[texture._myid];

		let sx: number = rect.x, sy: number = rect.y;
		let sw: number = rect.width, sh: number = rect.height;
        let id: string = texture._myid + spriteFrame.name;

        if (info) {
            // 已经在动态图集中
            sx += info.x;
			sy += info.y;
        }
        else {
            // 不在动态图集中，需要插入
            let width = texture.width, height = texture.height;        

            if ((this._x + width + space) > this._width) {
                this._x = space;
                this._y = this._nexty;
            }

            if ((this._y + height + space) > this._nexty) {
                this._nexty = this._y + height + space;
            }

            if (this._nexty > this._height) {
                return null;
            }

            // texture bleeding , 纹理之间预留空隙
            // if (cc.dynamicAtlasManager.textureBleeding) {
                // Smaller frame is more likely to be affected by linear filter
            if (width <= 8 || height <= 8) {
                this._texture['drawTextureAt'](texture, this._x-1, this._y-1);
                this._texture['drawTextureAt'](texture, this._x-1, this._y+1);
                this._texture['drawTextureAt'](texture, this._x+1, this._y-1);
                this._texture['drawTextureAt'](texture, this._x+1, this._y+1);
            }

            this._texture['drawTextureAt'](texture, this._x-1, this._y);
            this._texture['drawTextureAt'](texture, this._x+1, this._y);
            this._texture['drawTextureAt'](texture, this._x, this._y-1);
            this._texture['drawTextureAt'](texture, this._x, this._y+1);
            // }

            this._texture['drawTextureAt'](texture, this._x, this._y);

            this._innerTextureInfos[texture._myid] = {
                x: this._x,
                y: this._y,
                texture: texture
            };

            this._count++;

            sx += this._x;
            sy += this._y;

            this._x += width + space;

            this._dirty = true;
        }

        let frame = {
			rect: cc.rect(sx,sy,sw,sh),
            texture: this._texture,
            id: id,
            name: spriteFrame.name
        }
        

        return frame;
    }

    update () {
        if (!this._dirty) return;
        //@ts-ignore
        this._texture.update();
        this._dirty = false;
    }

    deleteInnerTexture (texture) {
        if (texture && this._innerTextureInfos[texture._id]) {
            delete this._innerTextureInfos[texture._id];
            this._count--;
        }
    }

    isEmpty () {
        return this._count <= 0;
    }
    
    // reset () {
    //     this._x = space;
    //     this._y = space;
    //     this._nexty = space;

    //     let frames = this._innerSpriteFrames;
    //     for (let i = 0, l = frames.length; i < l; i++) {
    //         let frame = frames[i];
    //         if (!frame.isValid) {
    //             continue;
    //         }
    //         frame._resetDynamicAtlasFrame();
    //     }
    //     this._innerSpriteFrames.length = 0;
    //     this._innerTextureInfos = {};
    // }

    destroy () {
        // this.reset();
        this._texture.destroy();
    }
}

