const defaultArr = [];
type HandlerObj = { handler: Function, target: any, isOnce: boolean ,args: any[] };

export class EventManager {

	private static _instance: EventManager;
	public static get instance(): EventManager{
		if(!this._instance){
			this._instance = new EventManager()
		}
		return this._instance
	}

    /** 记录当前正在分发事件中, 期间不处理on与off操作 */
    protected dispatchIdx: number;
    protected waitHandles: { handlerObj: HandlerObj, type: string, eventName: string | Symbol}[];

    public handlers : Map<string | Symbol, Array<HandlerObj>>;
    // public handlers:{[key:string]: Array<HandlerObj>} = {};

    constructor(){
        this.dispatchIdx = 0;
        this.waitHandles = [];
        this.handlers = new Map<string | Symbol , Array<HandlerObj>>();
    }

    public event(eventName: string, args1?,args2?,args3?,args4?,args5?,args6?,args7?,args8?){
        this.dispatch(eventName, args1,args2,args3,args4,args5,args6,args7,args8);
    }

    public once(eventName: string | Symbol, target: any, handler: Function){
        this.on(eventName, target, handler, true);
    }

    public on(eventName: string | Symbol, target: any, handler: Function,isOnce:boolean = false, args?: any[]) {
        // let handlerList = this.handlers[eventName];
        let handlerList = this.handlers.get(eventName);
        if (!handlerList) {
            handlerList = [];
            // this.handlers[eventName] = handlerList;
            this.handlers.set(eventName , handlerList);
        }
        const handlerObj = { handler: handler, target: target, isOnce: isOnce ,args:args};

        if(this.dispatchIdx){
            // 分发事件期间缓存操作
            this.waitHandles.push({handlerObj: handlerObj, type:'on', eventName: eventName})
            return;
        }
        
        for (let i = 0; i < handlerList.length; i++) {
            if(handlerList[i]){
                // 判断是否重复on
                if(handlerList[i].handler == handler && handlerList[i].target == target){
                    return i;
                }
            }
        }
        handlerList.unshift(handlerObj);  
        return handlerList.length;
    };

    /**
     * 
     * @param eventName GameEvent
     * @param args1 
     * @param args2 
     * @param args3 
     * @param args4 
     * @param args5 
     * @param args6 
     * @param args7 
     * @param args8 
     * @returns 
     */
    public dispatch(eventName: string | Symbol,  args1?,args2?,args3?,args4?,args5?,args6?,args7?,args8?) { // ...restOfName: any[]) { 优化费性能写法
        // let handlerList = this.handlers[eventName];
        let handlerList = this.handlers.get(eventName);
        if (!handlerList) {
            return;
        }
        try{ 
            // 记录当前正在分发事件中, 期间不处理on与off操作
            this.dispatchIdx ++;
            for (let i = handlerList.length - 1; i >= 0; i--) {
                if(!handlerList[i]){
                    // 分发事件期间调用off，会导致handlerList[i]为null
                    continue;
                }
                let handler = handlerList[i].handler;
                let target = handlerList[i].target;
                let isOnce = handlerList[i].isOnce;
                let args = handlerList[i].args || defaultArr;
                if (handler) {
                    if(isOnce){
                        handlerList.splice(i, 1);
                    }

                    if (target) {
                        handler.call(target, ...args, args1,args2,args3,args4,args5,args6,args7,args8)
                    } else {
                        handler(...args, args1,args2,args3,args4,args5,args6,args7,args8)
                    }
                }
            }
        }finally{
            this.dispatchIdx --;
            if(handlerList.length == 0){
                // delete this.handlers[eventName];
                this.handlers.delete(eventName);
            }
            /** 分发事件期间缓存的处理 */
            this.dispatchIdx == 0 && this.handleWaitEvent();
        }

        if(CC_DEBUG && this.dispatchIdx < 0) debugger;
    }

    // 清除一次性事件
    public clearOnceEvent(){
        // for (let eventName in this.handlers) {
        this.handlers.forEach((value , eventName)=>{
            // let handlerList = this.handlers[eventName];
            let handlerList = this.handlers.get(eventName);
            for (var i = handlerList.length - 1; i >=0 ; i--) {
                if (handlerList[i].isOnce) {
                    if(this.dispatchIdx){
                        // 分发事件期间缓存操作
                        this.waitHandles.push({handlerObj: handlerList[i], eventName: eventName, type: 'off'});
                    }else{
                        handlerList.splice(i, 1);
                    }
                }
            }
        });
            
        // }
    }

    public off(eventName: string | Symbol, target: any, handler: Function) {
        // let handlerList = this.handlers[eventName];
        let handlerList = this.handlers.get(eventName);
        if (!handlerList) {
            return;
        }
        for (let i = 0; i < handlerList.length; i++) {
            let oldHandler = handlerList[i].handler;
            let oldTarget = handlerList[i].target;
            if (oldHandler === handler && oldTarget === target) {
                
                if(this.dispatchIdx){
                    // 分发事件期间缓存操作
                    this.waitHandles.push({handlerObj: handlerList[i], eventName: eventName, type: 'off'});
                }else{
                    handlerList.splice(i, 1);
                }
                break;
            }
        }
    }
    
    public clear(target: any) {
        this.handlers.forEach((value , eventName)=>{
            // let handlerList = this.handlers[eventName];
            let handlerList = this.handlers.get(eventName);
            for (var i = handlerList.length-1; i >= 0 ; i--) {
                var oldTarget = handlerList[i].target;
                if (oldTarget === target) {
                    
                    if(this.dispatchIdx){
                        // 分发事件期间缓存操作
                        this.waitHandles.push({handlerObj: handlerList[i], eventName: eventName, type: 'off'});
                    }else{
                        handlerList.splice(i, 1);
                    }
                }
            }
        });   
    }

    public clearAll() {
        if(this.dispatchIdx){
            this.waitHandles.push({handlerObj: null, eventName: null, type: 'clearAll'});
        }else{
            this.handlers.clear();
        }
    }

    public offAll() {
        this.clearAll();
    }

    /** 处理分发事件期间缓存的操作 */
    protected handleWaitEvent(){
        if(!this.waitHandles.length){
            return;
        }
        try{
            for (let i = 0; i < this.waitHandles.length; i++) {
                const handle = this.waitHandles[i];
                if(handle.type == 'on'){
                    this.on(handle.eventName, handle.handlerObj.target, handle.handlerObj.handler, handle.handlerObj.isOnce,handle.handlerObj.args);
                }else if(handle.type == 'off'){
                    this.off(handle.eventName, handle.handlerObj.target, handle.handlerObj.handler);
                }else if(handle.type == 'clearAll'){
                    this.clearAll()
                }
            }
        }finally{
            this.waitHandles.length = 0;
        }
    }

    public removeBtnEvent(objectNode: cc.Node) {
        objectNode.removeComponent(cc.Button)
    }

    public removeBtnEffect(objectNode: cc.Node) {
        let b: cc.Button = objectNode.getComponent(cc.Button);
        b.transition = cc.Button.Transition.NONE;
    }

    public addBtnEffect(objectNode: cc.Node, scale: number = 1.1) {
        let b = objectNode.getComponent(cc.Button);
        b.transition = cc.Button.Transition.SCALE;
        b.zoomScale = scale;
    }
}
