import BasePlatformAPI from "./BasePlatformAPI";

export default class SceneAPI extends BasePlatformAPI {

    private static scene: SceneAPI = null;
    public static get Init(): SceneAPI {
        if (this.scene == null) {
            this.scene = new SceneAPI();
        }
        return this.scene;
    }

    /**
     * 显示消息提示框
     * @param title 提示的内容
     * @param icon 图标
     * @param duration 提示的延迟时间
     * @param mask 是否显示透明蒙层，防止触摸穿透
     */
     public ShowToast(title: string, icon: "success" | "loading" | "none", duration: number = 1500, mask: boolean = false) {
        if (!this.api) return console.log('ShowToast: ',title);
        this.api.showToast(
            {
                title : title,
                icon : icon,
                duration : duration,
                mask : mask
            }
        );
    }

    /**隐藏消息提示框 */
    public HideToast() {
        if (!this.api) return;
        this.api.hideToast();
    }

    /**
     * 显示 loading 提示框。需主动调用 wx.hideLoading 才能关闭提示框
     * @param title 提示的内容
     * @param mask 是否显示透明蒙层，防止触摸穿透
     */
     public ShowLoading(title: string, mask: boolean) {
        if (!this.api) return;
        this.api.showLoading({
            title : title,
            mask : mask
        });
    }

    /**隐藏 loading 提示框 */
    public HideLoading() {
        if (!this.api) return;
        this.api.hideLoading();
    }

    /**
     * 显示模态对话框
     * @param title 提示的标题
     * @param content 提示的内容
     * @param showcancel 是否显示取消按钮
     * @param canceltext 取消按钮的文字，最多 4 个字符
     * @param cancelcolor 取消按钮的文字颜色，必须是 16 进制格式的颜色字符串
     * @param confirmtext 确认按钮的文字，最多 4 个字符
     * @param confirmcolor 确认按钮的文字颜色，必须是 16 进制格式的颜色字符串
     */
    public ShowModal(
        title: string, 
        content: string, 
        showcancel: boolean = true, 
        canceltext: string = "取消",
        cancelcolor: string = "#000000", 
        confirmtext: string = "确认", 
        confirmcolor: string = "#576B95"): Promise<{ confirm: boolean, cancel: boolean }> 
    {
        if (!this.api) return new Promise((resolve, reject) => {
            reject();
        });
        return new Promise((r,j)=>{
            this.api.showModal({
                title : title,
                content : content,
                showCancel : showcancel,
                cancelText : canceltext,
                cancelColor : cancelcolor,
                confirmText : confirmtext,
                confirmColor : confirmcolor,
                success : (res)=>{
                    if(res.confirm){
                        r(res);
                    }else if(res.cancel){
                        j(res);
                    }
                }
            });
        });     
    }
}